import argparse
from confluent_kafka import Producer
from confluent_kafka.admin import AdminClient, NewTopic


def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration')

    parser.add_argument('--topic', help='Topic name to create.', required=True)
    parser.add_argument('--partitions', type=int, default=1,
                        help='Number of partitions for the topic.')
    parser.add_argument('--replication-factor', type=int, default=3,
                        help='Replication factor for the topic.')

    args = parser.parse_args()

    # Create a new topic with the provided configuration.
    new_topic = NewTopic(
        name=args.topic,
        num_partitions=args.partitions,
        replication_factor=args.replication_factor)

    # Configure the AdminClient to connect to the Kafka cluster.
    admin_client = AdminClient({'bootstrap.servers': 'localhost:9092'})

    # Create a new topic with the provided configuration.
    try:
        result = admin_client.create_topics([new_topic])

        print('Created topic {} with {} partitions and replication factor {}'.format(
            args.topic, args.partitions, args.replication_factor))
    except Exception as e:
        print("Error while creating topic: {}".format(e))


if __name__ == '__main__':
    main()